<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        body {
            background-color: #121212;
            color: #e0e0e0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            margin: 0;
            height: 100vh;
            overflow: hidden;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
            background: #1e1e1e;
            border-radius: 12px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        canvas {
            background-color: #000;
            border: 4px solid #333;
            border-radius: 4px;
            cursor: crosshair;
            image-rendering: pixelated;
            width: 500px;
            height: 500px;
        }

        .controls {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 10px 20px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            transition: transform 0.1s, background 0.2s, box-shadow 0.2s;
            text-transform: uppercase;
            font-size: 12px;
            letter-spacing: 1px;
        }

        button:active {
            transform: scale(0.95);
        }

        /* Material Colors */
        #mat-sand { background: #f0d060; color: #333; }
        #mat-water { background: #40a0ff; color: #fff; }
        #mat-wall { background: #808080; color: #fff; }
        #mat-acid { background: #40ff40; color: #333; }
        #mat-empty { background: #333; color: #fff; }
        #clear { background: #ff4040; color: #fff; margin-left: 20px; }

        button.active {
            outline: 3px solid white;
            box-shadow: 0 0 10px rgba(255,255,255,0.5);
        }
    </style>
</head>
<body>

<div class="container">
    <canvas id="sand" width="100" height="100"></canvas>
    <div class="controls">
        <button id="mat-sand" onclick="setMaterial('sand')">Sand</button>
        <button id="mat-water" onclick="setMaterial('water')">Water</button>
        <button id="mat-wall" onclick="setMaterial('wall')">Wall</button>
        <button id="mat-acid" onclick="setMaterial('acid')">Acid</button>
        <button id="mat-empty" onclick="setMaterial('empty')">Eraser</button>
        <button id="clear" onclick="sim.clear()">Clear Grid</button>
    </div>
</div>

<script>
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false });
    const W = 100;
    const H = 100;

    let grid = Array.from({ length: H }, () => Array(W).fill('empty'));
    let currentMaterial = 'sand';
    let isMouseDown = false;

    const COLORS = {
        empty: '#000000',
        sand: '#f0d060',
        water: '#40a0ff',
        wall: '#808080',
        acid: '#40ff40'
    };

    // API Implementation
    window.sim = {
        w: W,
        h: H,
        get(x, y) {
            if (x < 0 || x >= W || y < 0 || y >= H) return 'wall';
            return grid[y][x];
        },
        set(x, y, material) {
            if (x >= 0 && x < W && y >= 0 && y < H) {
                grid[y][x] = material;
            }
        },
        clear() {
            grid = Array.from({ length: H }, () => Array(W).fill('empty'));
        },
        tick(n) {
            for (let i = 0; i < n; i++) {
                this._step();
            }
        },
        _step() {
            // Process bottom-up to prevent teleporting
            const moved = Array.from({ length: H }, () => Array(W).fill(false));

            for (let y = H - 1; y >= 0; y--) {
                // Randomize X direction each tick for natural spreading
                const xDir = Math.random() < 0.5 ? 1 : -1;
                for (let x = 0; x < W; x++) {
                    const currentX = (xDir === 1) ? x : (W - 1 - x);
                    const mat = grid[y][currentX];

                    if (mat === 'empty' || mat === 'wall') continue;
                    if (moved[y][currentX]) continue;

                    if (mat === 'sand') {
                        this.handleSand(currentX, y, moved);
                    } else if (mat === 'water') {
                        this.handleLiquid(currentX, y, moved, false);
                    } else if (mat === 'acid') {
                        this.handleLiquid(currentX, y, moved, true);
                    }
                }
            }
        },
        handleSand(x, y, moved) {
            // 1. Fall straight down or sink in liquids
            const below = this.get(x, y + 1);
            if (below === 'empty' || below === 'water' || below === 'acid') {
                this.swap(x, y, x, y + 1);
                moved[y+1][x] = true;
                return;
            }

            // 2. Slide diagonally
            const dir = Math.random() < 0.5 ? 1 : -1;
            for (let i = 0; i < 2; i++) {
                const dx = i === 0 ? dir : -dir;
                const diag = this.get(x + dx, y + 1);
                if (diag === 'empty' || diag === 'water' || diag === 'acid') {
                    this.swap(x, y, x + dx, y + 1);
                    moved[y+1][x+dx] = true;
                    return;
                }
            }
        },
        handleLiquid(x, y, moved, isAcid) {
            // Acid dissolution check (below and sides)
            if (isAcid) {
                const targets = [[0, 1], [-1, 0], [1, 0]];
                for (let [dx, dy] of targets) {
                    const targetMat = this.get(x + dx, y + dy);
                    if (targetMat === 'sand' || targetMat === 'wall') {
                        this.set(x + dx, y + dy, 'empty');
                        this.set(x, y, 'empty'); // Acid is consumed in reaction
                        moved[y][x] = true;
                        return;
                    }
                }
            }

            // Movement logic (same for water and acid)
            const below = this.get(x, y + 1);
            if (below === 'empty') {
                this.swap(x, y, x, y + 1);
                moved[y+1][x] = true;
                return;
            }

            // Spread horizontally
            const dir = Math.random() < 0.5 ? 1 : -1;
            for (let i = 0; i < 2; i++) {
                const dx = i === 0 ? dir : -dir;
                if (this.get(x + dx, y) === 'empty') {
                    this.swap(x, y, x + dx, y);
                    moved[y][x+dx] = true;
                    return;
                }
            }
        },
        swap(x1, y1, x2, y2) {
            const temp = grid[y1][x1];
            grid[y1][x1] = grid[y2][x2];
            grid[y2][x2] = temp;
        }
    };

    function setMaterial(m) {
        currentMaterial = m;
        document.querySelectorAll('.controls button').forEach(btn => btn.classList.remove('active'));
        document.getElementById(`mat-${m}`).classList.add('active');
    }

    // Input Handling
    function paint(e) {
        const rect = canvas.getBoundingClientRect();
        const scaleX = W / rect.width;
        const scaleY = H / rect.height;
        const x = Math.floor((e.clientX - rect.left) * scaleX);
        const y = Math.floor((e.clientY - rect.top) * scaleY);
        sim.set(x, y, currentMaterial);
    }

    canvas.addEventListener('mousedown', (e) => { isMouseDown = true; paint(e); });
    window.addEventListener('mouseup', () => { isMouseDown = false; });
    canvas.addEventListener('mousemove', (e) => { if (isMouseDown) paint(e); });

    // Rendering Loop
    function render() {
        sim.tick(1);

        // Use ImageData for performance on 100x100 grid
        const imgData = ctx.createImageData(W, H);
        const data = imgData.data;

        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                const mat = grid[y][x];
                const color = COLORS[mat];
                const r = parseInt(color.slice(1, 3), 16);
                const g = parseInt(color.slice(3, 5), 16);
                const b = parseInt(color.slice(5, 7), 16);
                const idx = (y * W + x) * 4;
                data[idx] = r;
                data[idx+1] = g;
                data[idx+2] = b;
                data[idx+3] = 255;
            }
        }
        ctx.putImageData(imgData, 0, 0);
        requestAnimationFrame(render);
    }

    // Init
    setMaterial('sand');
    render();
</script>
</body>
</html>
